macro_rules! say_hello {
    // Matches no arguments
    () => {
        println!("Hello!");
    };
    // Matches one expression argument
    ($name:expr) => {
        println!("Hello, {}!", $name);
    };
}

fn main() {
    say_hello!();
    say_hello!("Rustacean");
}

macro_rules! create_map {
    // Match keys ($k) and values ($v), separated by =>, 
    // and the whole pair separated by commas
    ( $( $k:expr => $v:expr ),* ) => {
        {
            let mut map = std::collections::HashMap::new();
            $(
                map.insert($k, $v);
            )*
            map
        }
    };
}

fn main() {
    let scores = create_map!(
        "Blue" => 10,
        "Red" => 50,
        "Green" => 20
    );

    println!("Scores: {:?}", scores);
}

